// Extract structured data from the Retell post-call payload
const body = $json.body || $json;
const callData = body.call || body;
const transcript = callData.transcript || '';
const customData = callData.call_analysis || callData.custom_analysis_data || {};
const metadata = callData.metadata || callData.dynamic_variables || {};

// Fields to extract — these come from Retell's call_analysis if configured,
// or we parse from transcript in the next LLM node.
const extracted = {
  retell_call_id: callData.call_id || '',
  from_number: callData.from_number || metadata.caller_phone || '',
  to_number: callData.to_number || '',
  started_at: callData.start_timestamp || null,
  ended_at: callData.end_timestamp || null,
  duration_sec: callData.duration_ms ? Math.round(callData.duration_ms / 1000) : null,
  transcript: transcript,
  recording_url: callData.recording_url || '',
  transferred: callData.call_status === 'transferred' || false,

  // From call_analysis (Retell structured extraction)
  intent: customData.intent || 'unknown',
  urgency: customData.urgency || 'low',
  customer_name: customData.customer_name || metadata.customer_name || '',
  phone: callData.from_number || metadata.caller_phone || '',
  year: customData.vehicle_year || null,
  make: customData.vehicle_make || '',
  model: customData.vehicle_model || '',
  issue_summary: customData.issue_summary || '',
  vehicle_drivable: customData.vehicle_drivable || 'unknown',
  preferred_day: customData.preferred_day || '',
  preferred_time: customData.preferred_time || '',
  needs_tow: customData.needs_tow || false,
  existing_customer: metadata.returning_customer === 'yes',
  human_transfer_requested: customData.human_transfer_requested || false,
  sentiment: customData.sentiment || 'neutral',
  follow_up_type: customData.follow_up_type || 'none',

  // Shop context
  shop_name: metadata.shop_name || '',
  shop_number: callData.to_number || '',
  after_hours: metadata.shop_is_open === 'false'
};

return { json: extracted };

const extracted = $node['Extract Call Fields'].json;

// Only upsert vehicle if we have at least make or model
if (!extracted.make && !extracted.model) {
  return { json: { vehicle_id: null, skip: true } };
}

return { json: { 
  caller_id: $node['Upsert Caller'].json[0]?.id || $node['Upsert Caller'].json.id,
  year: extracted.year,
  make: extracted.make,
  model: extracted.model,
  drivable_status: extracted.vehicle_drivable,
  skip: false
} };

const extracted = $node['Extract Call Fields'].json;
const intent = extracted.intent;
const urgency = extracted.urgency;
const shopId = $node['Get Shop ID'].json[0]?.id || $node['Get Shop ID'].json.id;
const callerId = $node['Upsert Caller'].json[0]?.id || $node['Upsert Caller'].json.id;
const callId = $node['Insert Call Record'].json[0]?.id || $node['Insert Call Record'].json.id;

const result = {
  intent,
  urgency,
  shop_id: shopId,
  caller_id: callerId,
  call_id: callId,
  create_appointment: false,
  create_task: false,
  task_type: null,
  task_priority: 'medium',
  sms_template: null,
  alert_staff: false
};

// Route by intent
switch (intent) {
  case 'new_appointment':
    result.create_appointment = true;
    result.create_task = true;
    result.task_type = 'appointment_confirm';
    result.sms_template = 'booking_request_captured';
    if (extracted.preferred_day && extracted.preferred_day.toLowerCase().includes('today')) {
      result.task_priority = 'high';
    }
    break;

  case 'existing_status':
    result.create_task = true;
    result.task_type = 'status_followup';
    result.task_priority = 'medium';
    result.sms_template = 'status_request_received';
    break;

  case 'price_question':
    result.create_appointment = !!extracted.make; // only if vehicle captured
    result.create_task = true;
    result.task_type = 'callback';
    result.sms_template = 'booking_request_captured';
    break;

  case 'urgent_breakdown':
  case 'tow_request':
    result.create_task = true;
    result.task_type = 'urgent_callback';
    result.task_priority = 'urgent';
    result.sms_template = 'urgent_callback';
    result.alert_staff = true;
    break;

  case 'angry_customer':
    result.create_task = true;
    result.task_type = 'callback';
    result.task_priority = 'high';
    result.sms_template = 'urgent_callback';
    result.alert_staff = true;
    break;

  case 'hours_address':
    result.sms_template = 'hours_address_reply';
    break;

  case 'vendor_sales':
  case 'wrong_number':
    // No action needed
    break;

  default:
    result.create_task = true;
    result.task_type = 'callback';
    break;
}

// After-hours override: tasks become callbacks
if (extracted.after_hours && result.create_task) {
  if (result.task_type === 'appointment_confirm') {
    result.sms_template = 'after_hours_intake_confirmation';
  }
}

return { json: result };

const route = $node['Route by Intent'].json;
const extracted = $node['Extract Call Fields'].json;
const template = route.sms_template;

if (!template || !extracted.phone) {
  return { json: { skip: true } };
}

// SMS templates
const templates = {
  booking_request_captured: `Hi ${extracted.customer_name || 'there'}, thanks for calling ${extracted.shop_name}! We've received your appointment request for your ${extracted.year || ''} ${extracted.make || ''} ${extracted.model || ''}. We'll confirm your time shortly.`,

  urgent_callback: `Hi ${extracted.customer_name || 'there'}, we received your call about an urgent issue with your ${extracted.year || ''} ${extracted.make || ''} ${extracted.model || ''}. A team member will call you back as soon as possible. If this is an emergency, please call 911.`,

  status_request_received: `Hi ${extracted.customer_name || 'there'}, thanks for calling ${extracted.shop_name}. We've noted your request for a status update. A service advisor will reach out to you shortly.`,

  hours_address_reply: `${extracted.shop_name} is located at ${$node['Extract Call Fields'].json.shop_name ? '' : 'our shop'}. ${extracted.shop_name || 'We'} look forward to seeing you!`,

  after_hours_intake_confirmation: `Hi ${extracted.customer_name || 'there'}, thanks for calling ${extracted.shop_name} after hours. We've captured your info and someone will reach out when the shop opens. Thanks for your patience!`,

  missed_call_followup: `Hi, we noticed we missed your call at ${extracted.shop_name}. How can we help? Reply to this message or call us back anytime.`
};

const smsBody = templates[template] || `Thanks for calling ${extracted.shop_name}. We'll be in touch!`;

return { json: {
  skip: false,
  to: extracted.phone,
  body: smsBody,
  template: template,
  shop_id: route.shop_id,
  caller_id: route.caller_id,
  call_id: route.call_id
} };
